SELECT FROM meal_item
source_type = 'PERSONAL' AND owner_user_id = #{userId}
source_type = 'PUBLIC' AND owner_user_id IS NULL
AND (#{mealTimeJson} = '[]' OR JSON_OVERLAPS(meal_time, #{mealTimeJson})) AND (#{moodJson} = '[]' OR JSON_OVERLAPS(mood, #{moodJson})) AND (#{sceneJson} = '[]' OR JSON_OVERLAPS(scene, #{sceneJson})) AND (#{healthGoalJson} = '[]' OR JSON_OVERLAPS(health_goal, #{healthGoalJson})) AND (#{cuisineJson} = '[]' OR JSON_OVERLAPS(cuisine, #{cuisineJson})) AND (#{tasteJson} = '[]' OR JSON_OVERLAPS(taste, #{tasteJson})) AND (#{convenienceJson} = '[]' OR JSON_OVERLAPS(convenience, #{convenienceJson}))
ORDER BY updated_at DESC LIMIT #{limit}
